import { formatTrademarkSymbols } from "@/lib/textFormatting";
import { useParams, Link, useLocation, useNavigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from "@/components/ui/dropdown-menu";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { toast } from "sonner";
import { Star, MapPin, Phone, Clock, Heart, Navigation, ChevronLeft, Loader2, MessageCircle, Wallet, Edit, ShieldAlert, Share2, Link2, ChevronDown, ShoppingBag, CalendarDays, ExternalLink, UtensilsCrossed, Globe, Languages, RotateCcw, BadgeCheck, HandMetal, FileText } from "lucide-react";
import { useRestaurant, useToggleFavorite, useFavorites } from "@/hooks/useRestaurants";
import { useComments } from "@/hooks/useComments";
import { useAuth } from "@/contexts/AuthContext";
import { useTranslation } from "react-i18next";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { formatAllOpeningHours, formatOpeningHours } from "@/lib/timeUtils";
import { openNavigation, calculateDistance, getUserLocation } from "@/lib/geolocation";
import { isIOSWebView, isIOSDevice, openExternalUrl } from "@/lib/externalLinks";
// NavigationConfirmDialog removed - using inline glass-style AlertDialog instead
import { supabase } from "@/integrations/supabase/client";
import RestaurantRating from "@/components/RestaurantRating";
import ReportDialog from "@/components/ReportDialog";
import mapboxgl from "mapbox-gl";
import mapIcon from "@/assets/map-icon.png";
import { useEffect, useRef, useState, useMemo, useCallback, lazy, Suspense } from "react";
import { useQueryClient } from "@tanstack/react-query";
import { PullToRefresh } from "@/components/PullToRefresh";
import { usePageView } from "@/hooks/usePageView";
import { useSmartShare, ShareDrawer } from "@/components/ShareDrawer";

// Lazy load heavy components
const RestaurantComments = lazy(() => import("@/components/RestaurantComments"));
import { useUserRole } from "@/hooks/useUserRole";
import { useMerchantRestaurants } from "@/hooks/useActivityParticipation";
import { RestaurantFormDialog } from "@/components/admin/RestaurantFormDialog";
import { useRestaurantActivities, getLocalizedBadgeText, getLocalizedActivityTitle, getLocalizedIntro } from "@/hooks/useRestaurantActivities";
import { useIsMobile } from "@/hooks/use-mobile";
import { RestaurantDishGallery } from "@/components/RestaurantDishGallery";
import { RestaurantDetailSkeleton } from "@/components/skeletons";
import { GhostRestaurantHero } from "@/components/GhostRestaurantHero";
import { GhostRestaurantStory } from "@/components/GhostRestaurantStory";
import { BrandAboutSection } from "@/components/BrandAboutSection";
import { BuildingStorySection, getBuildingStoryParts } from "@/components/BuildingStorySection";
import { useStoryTranslation, useAutoTranslateNarrative } from "@/components/IChingSection";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import ClaimRestaurantDialog from "@/components/ClaimRestaurantDialog";
import ImagePreviewModal from "@/components/ImagePreviewModal";
import { useLoginRequired } from "@/hooks/useLoginRequired";
import StoreAdBanner from "@/components/StoreAdBanner";
import { useAutoTranslateNames } from "@/hooks/useAutoTranslateNames";
import { LandmarkDetailPage } from "@/components/LandmarkDetailPage";
import { useSmartBack } from "@/hooks/useSmartBack";

const RestaurantDetail = () => {
  const { id } = useParams<{ id: string }>();
  const location = useLocation();
  const { t, i18n } = useTranslation();
  const { user } = useAuth();
  const { localizeRestaurant, getLocalizedField } = useLocalizedContent();
  const isMobile = useIsMobile();
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<mapboxgl.Map | null>(null);
  const [distance, setDistance] = useState<number | null>(null);
  const [hoursOpen, setHoursOpen] = useState(false);
  const [mapOpen, setMapOpen] = useState(false);
  const [announcementOpen, setAnnouncementOpen] = useState(false);
  const [activitiesOpen, setActivitiesOpen] = useState(false);
  const [shouldLoadMap, setShouldLoadMap] = useState(true);
  const [shouldLoadComments, setShouldLoadComments] = useState(true);
  const [isGeneratingToken, setIsGeneratingToken] = useState(false);
  const mapSectionRef = useRef<HTMLDivElement>(null);
  const commentsSectionRef = useRef<HTMLDivElement>(null);
  const [showNavigationDialog, setShowNavigationDialog] = useState(false);
  const [showLoginDialog, setShowLoginDialog] = useState(false);
  const [showOrderDialog, setShowOrderDialog] = useState(false);
  const [orderDialogType, setOrderDialogType] = useState<'takeaway' | 'booking'>('takeaway');
  const [showPrivateDialog, setShowPrivateDialog] = useState(false);
  const [verifiedDialog, setVerifiedDialog] = useState(false);
  const [claimDialog, setClaimDialog] = useState<{ id: string; name: string; address: string } | null>(null);
  const { requireLogin } = useLoginRequired();
  const [menuPreviewUrl, setMenuPreviewUrl] = useState<string | null>(null);
  const [translatedDescription, setTranslatedDescription] = useState<string | null>(null);
  const [translatedName, setTranslatedName] = useState<string | null>(null);
  const [translatedAddress, setTranslatedAddress] = useState<string | null>(null);
  const [translatedOwnerBio, setTranslatedOwnerBio] = useState<string | null>(null);
  const [isGhostTranslating, setIsGhostTranslating] = useState(false);
  const [isRegularTranslating, setIsRegularTranslating] = useState(false);
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const { share: smartShareFn, DrawerComponent: SmartShareDrawer } = useSmartShare();

  // Pull-to-refresh handler - clears cache and forces fresh data
  const handleRefresh = useCallback(async () => {
    // Clear caches first
    queryClient.removeQueries({ queryKey: ['restaurant', id] });
    queryClient.removeQueries({ queryKey: ['comments', id] });
    queryClient.removeQueries({ queryKey: ['restaurant-activities', id] });
    queryClient.removeQueries({ queryKey: ['dish-images', id] });
    
    // Refetch with fresh data
    await Promise.all([
      queryClient.invalidateQueries({ queryKey: ['restaurant', id] }),
      queryClient.invalidateQueries({ queryKey: ['comments', id] }),
      queryClient.invalidateQueries({ queryKey: ['restaurant-activities', id] }),
      queryClient.invalidateQueries({ queryKey: ['dish-images', id] }),
    ]);
  }, [queryClient, id]);

  // Track page view
  usePageView({ pageType: "restaurant", targetId: id });
  
  // Smart back navigation - uses browser history when available, fallback to /restaurants
  const goBack = useSmartBack("/restaurants");

  const { data: restaurant, isLoading } = useRestaurant(id!);

  const { data: favoriteIds = [] } = useFavorites();
  const { data: comments } = useComments(id!, "restaurant", { enabled: shouldLoadComments });
  const toggleFavorite = useToggleFavorite();
  const { role, isAdmin } = useUserRole();
  const { data: myRestaurants = [] } = useMerchantRestaurants();
  const { data: restaurantActivities = [] } = useRestaurantActivities(id!);
  
  // Check if current user is merchant of this restaurant
  const isMerchantOfRestaurant = restaurant && myRestaurants.some(r => r.id === restaurant.id);

  const localizedRestaurant = restaurant ? localizeRestaurant(restaurant) : null;
  const isFavorite = restaurant ? favoriteIds.includes(restaurant.id) : false;

  // Auto-translate restaurant name for non-zh/en/pt languages
  const singleRestaurantArray = useMemo(() => restaurant ? [restaurant] : undefined, [restaurant]);
  useAutoTranslateNames(singleRestaurantArray, useCallback((translations) => {
    if (translations && restaurant) {
      const entry = translations[restaurant.id];
      if (entry) {
        const name = entry.split('\n')[0];
        if (name && name !== localizedRestaurant?.name) {
          setTranslatedName(name);
        }
      }
    }
  }, [restaurant?.id, localizedRestaurant?.name]));

  // Unified story translation (narrative only, I Ching has its own manual button)
  const { buildingNarrative, iChingFull } = useMemo(
    () => restaurant ? getBuildingStoryParts(restaurant as any, i18n.language) : { buildingNarrative: "", iChingFull: null },
    [restaurant, i18n.language]
  );
  const { narrativeDisplay, iChingDisplay: _iChingDisplay, translateStory, isTranslating: isStoryTranslating, showTranslation: showStoryTranslation } = useStoryTranslation(
    buildingNarrative || "",
    "" // Pass empty string for I Ching - it handles its own translation now
  );

  // Calculate most common price range from comments
  const priceRanges = useMemo(() => [
    { value: "€", label: "€ (0-10€)" },
    { value: "€€", label: "€€ (10-20€)" },
    { value: "€€€", label: "€€€ (20€+)" },
  ], []);
  
  const mostCommonPriceRange = useMemo(() => {
    const stats: Record<string, { count: number; latestDate: string }> = {};
    comments?.forEach(comment => {
      if (comment.price_range) {
        if (!stats[comment.price_range]) {
          stats[comment.price_range] = { count: 0, latestDate: comment.created_at };
        }
        stats[comment.price_range].count += 1;
        // Keep track of the most recent date for this price range
        if (comment.created_at > stats[comment.price_range].latestDate) {
          stats[comment.price_range].latestDate = comment.created_at;
        }
      }
    });
    return stats;
  }, [comments]);
  
  // Calculate total price range count
  const totalPriceRangeCount = useMemo(() => {
    if (!mostCommonPriceRange) return 0;
    return Object.values(mostCommonPriceRange).reduce((sum, item) => sum + item.count, 0);
  }, [mostCommonPriceRange]);
  
  // Only display price range if there are more than 10 data points
  // If counts are equal, use the one with the most recent comment
  const priceRangeDisplay = useMemo(() => {
    if (!mostCommonPriceRange || totalPriceRangeCount < 10) return null;
    const sorted = Object.entries(mostCommonPriceRange).sort(([, a], [, b]) => {
      // Sort by count first (descending)
      if (b.count !== a.count) return b.count - a.count;
      // If counts are equal, sort by latest date (descending)
      return b.latestDate.localeCompare(a.latestDate);
    });
    return sorted[0]?.[0] || null;
  }, [mostCommonPriceRange, totalPriceRangeCount]);

  // Calculate rating count and average rating from comments (comments with rating_value)
  const { ratingCount, averageRating } = useMemo(() => {
    const ratedComments = comments?.filter(c => c.rating_value) || [];
    const count = ratedComments.length;
    const avg = count > 0 
      ? ratedComments.reduce((sum, c) => sum + (c.rating_value || 0), 0) / count 
      : 0;
    return { ratingCount: count, averageRating: avg };
  }, [comments]);

  // Calculate distance from user location
  useEffect(() => {
    if (!restaurant) return;
    
    getUserLocation()
      .then((position) => {
        const dist = calculateDistance(
          position.coords.latitude,
          position.coords.longitude,
          restaurant.lat,
          restaurant.lng
        );
        setDistance(dist);
      })
      .catch(() => {
        // Silently fail if location not available
        setDistance(null);
      });
  }, [restaurant]);

  const handleToggleFavorite = useCallback(() => {
    if (!user || !restaurant) return;
    toggleFavorite.mutate(restaurant.id);
  }, [user, restaurant, toggleFavorite]);

  const handleCopyLink = useCallback(async () => {
    try {
      await navigator.clipboard.writeText(window.location.href);
      toast.success(t("common.linkCopied"));
    } catch (error) {
      console.error("Error copying link:", error);
      toast.error(t("common.shareError"));
    }
  }, [t]);

  const handleNativeShare = useCallback(async () => {
    if (!restaurant || !localizedRestaurant) return;
    
    smartShareFn({
      title: localizedRestaurant.name,
      text: `${localizedRestaurant.name} - Xiaoxiong Market\n\n${localizedRestaurant.description || localizedRestaurant.address}`,
      url: window.location.href,
    }, () => {
      toast.success(t("common.shareSuccess"));
    });
  }, [restaurant, localizedRestaurant, smartShareFn, t]);

  const handleShareToPlatform = useCallback((platform: string) => {
    if (!restaurant || !localizedRestaurant) return;
    
    const url = encodeURIComponent(window.location.href);
    const text = encodeURIComponent(localizedRestaurant.name);
    
    let shareUrl = "";
    
    switch (platform) {
      case "whatsapp":
        shareUrl = `https://wa.me/?text=${text}%20${url}`;
        break;
      case "facebook":
        shareUrl = `https://www.facebook.com/sharer/sharer.php?u=${url}`;
        break;
      case "twitter":
        shareUrl = `https://twitter.com/intent/tweet?text=${text}&url=${url}`;
        break;
      case "telegram":
        shareUrl = `https://t.me/share/url?url=${url}&text=${text}`;
        break;
      case "wechat":
        handleCopyLink();
        toast.info(t("common.shareVia") + " WeChat");
        return;
      default:
        return;
    }
    
    // Use appropriate method based on environment
    if (isIOSWebView()) {
      window.location.href = shareUrl;
    } else {
      window.open(shareUrl, "_blank", "width=600,height=400");
    }
  }, [restaurant, localizedRestaurant, handleCopyLink, t]);

  // Setup Intersection Observer for lazy loading
  useEffect(() => {
    const mapObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting && !shouldLoadMap) {
            setShouldLoadMap(true);
          }
        });
      },
      { rootMargin: "100px" }
    );

    const commentsObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting && !shouldLoadComments) {
            setShouldLoadComments(true);
          }
        });
      },
      { rootMargin: "200px" }
    );

    if (mapSectionRef.current) {
      mapObserver.observe(mapSectionRef.current);
    }
    if (commentsSectionRef.current) {
      commentsObserver.observe(commentsSectionRef.current);
    }

    return () => {
      mapObserver.disconnect();
      commentsObserver.disconnect();
    };
  }, [shouldLoadMap, shouldLoadComments]);

  // Initialize map
  useEffect(() => {
    if (!mapContainer.current || !restaurant || !shouldLoadMap || !mapOpen) return;
    
    // Don't initialize if map already exists
    if (map.current) return;

    const token = import.meta.env.VITE_MAPBOX_TOKEN;
    if (!token) {
      console.warn('[RestaurantDetail Map] No Mapbox token found');
      return;
    }

    // Check WebGL support
    if (!mapboxgl.supported()) {
      console.warn('[RestaurantDetail Map] WebGL not supported', {
        isIOSDevice: isIOSDevice(),
        isIOSWebView: isIOSWebView(),
        userAgent: navigator.userAgent
      });
      return;
    }

    // Wait for container to have dimensions
    const initMap = () => {
      if (!mapContainer.current) return;
      
      const rect = mapContainer.current.getBoundingClientRect();
      
      if (rect.width === 0 || rect.height === 0) {
        // Retry after a short delay
        setTimeout(initMap, 100);
        return;
      }

      try {
        mapboxgl.accessToken = token;

        map.current = new mapboxgl.Map({
          container: mapContainer.current,
          style: "mapbox://styles/mapbox/light-v11",
          center: [restaurant.lng, restaurant.lat],
          zoom: 15,
          cooperativeGestures: true, // Require two fingers to pan and zoom on mobile
        });

        map.current.on('error', (e) => {
          console.error('[RestaurantDetail Map] Map error:', e);
        });

        // Add custom marker with icon
        const el = document.createElement('div');
        el.style.backgroundImage = `url(${mapIcon})`;
        el.style.width = '40px';
        el.style.height = '40px';
        el.style.backgroundSize = 'contain';
        el.style.backgroundRepeat = 'no-repeat';
        el.style.backgroundPosition = 'center';
        el.style.cursor = 'pointer';

        new mapboxgl.Marker({ element: el })
          .setLngLat([restaurant.lng, restaurant.lat])
          .addTo(map.current);

        map.current.addControl(new mapboxgl.NavigationControl());
      } catch (error) {
        console.error('[RestaurantDetail Map] Failed to initialize map:', error);
      }
    };

    // Small delay to ensure Collapsible animation is complete
    setTimeout(initMap, 50);

    return () => {
      map.current?.remove();
      map.current = null;
    };
  }, [restaurant, shouldLoadMap, mapOpen]);

  // Handle map resize when toggling visibility
  useEffect(() => {
    if (mapOpen && map.current) {
      // Wait for collapsible animation to complete before resizing
      const timer = setTimeout(() => {
        map.current?.resize();
        // Re-center the map after resize
        if (restaurant) {
          map.current?.setCenter([restaurant.lng, restaurant.lat]);
        }
      }, 350);
      
      return () => clearTimeout(timer);
    }
  }, [mapOpen, restaurant]);

  if (isLoading) {
    return <RestaurantDetailSkeleton />;
  }

  if (!restaurant || !localizedRestaurant) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <p className="text-xl text-muted-foreground">{t("error.notFound")}</p>
          <Button className="mt-4" onClick={goBack}>
            {t("common.back")}
          </Button>
        </div>
      </div>
    );
  }

  const isGhostRestaurant = (restaurant as any).template === 'ghost' || (restaurant as any).template === 'michelin';

  // Ghost Restaurant - Immersive storytelling layout
  if (isGhostRestaurant) {
    // Ghost restaurant translate handler
    const handleGhostTranslate = async () => {
      const targetLang = i18n.language;
      // Toggle off
      if (showStoryTranslation) {
        setTranslatedName(null);
        setTranslatedAddress(null);
        setTranslatedDescription(null);
        setTranslatedOwnerBio(null);
        translateStory(targetLang);
        return;
      }
      setIsGhostTranslating(true);
      try {
        // Translate name + description + owner_bio together
        const ownerBio = restaurant?.owner_bio || '';
        const parts = [localizedRestaurant.name];
        const desc = localizedRestaurant.description?.replace(/<[^>]*>/g, '').trim();
        if (desc) parts.push(localizedRestaurant.description);
        if (ownerBio.trim()) parts.push(ownerBio);
        const combined = parts.join('\n---SECTION---\n');
        try {
          const { data, error } = await supabase.functions.invoke('translate-content', {
            body: { text: combined, targetLang }
          });
          if (!error && data?.translatedText) {
            const splitParts = data.translatedText.split(/---SECTION---/);
            let idx = 0;
            setTranslatedName(splitParts[idx]?.trim() || null);
            idx++;
            if (desc) { setTranslatedDescription(splitParts[idx]?.trim() || null); idx++; }
            if (ownerBio.trim()) { setTranslatedOwnerBio(splitParts[idx]?.trim() || null); }
          }
        } catch {}
        await translateStory(targetLang);
      } finally {
        setIsGhostTranslating(false);
      }
    };

    return (
      <div className="min-h-screen bg-background">
        {/* Hero Section */}
        <GhostRestaurantHero
          restaurant={restaurant}
          localizedRestaurant={localizedRestaurant}
          onBack={goBack}
          user={user}
          isFavorite={isFavorite}
          onToggleFavorite={handleToggleFavorite}
          onShare={() => {
            if (!user) {
              setShowLoginDialog(true);
              return;
            }
            if (isMobile && navigator.share) {
              handleNativeShare();
            } else {
              handleCopyLink();
            }
          }}
          onReport={() => {}}
          showEditButton={isMerchantOfRestaurant || isAdmin}
          editButton={(isMerchantOfRestaurant || isAdmin) && restaurant ? (
            <RestaurantFormDialog
              restaurant={restaurant}
              trigger={
                <Button
                  variant="secondary"
                  size="icon"
                  className="backdrop-blur-sm bg-background/60"
                >
                  <Edit className="w-5 h-5" />
                </Button>
              }
            />
          ) : null}
          reportButton={restaurant ? (
            <ReportDialog
              targetType="restaurant"
              targetId={restaurant.id}
              onLoginRequired={() => setShowLoginDialog(true)}
              trigger={
                <Button
                  variant="secondary"
                  size="icon"
                  className="backdrop-blur-sm bg-background/60"
                >
                  <ShieldAlert className="w-5 h-5" />
                </Button>
              }
            />
          ) : null}
          translatedName={translatedName}
          translatedDescription={translatedDescription}
          translatedOwnerBio={translatedOwnerBio}
          isTranslating={isStoryTranslating || isGhostTranslating}
          showTranslation={showStoryTranslation}
          onTranslate={handleGhostTranslate}
        />

        {/* Story Content */}
        <GhostRestaurantStory
          restaurant={restaurant}
          localizedRestaurant={localizedRestaurant}
          restaurantActivities={restaurantActivities}
          ratingCount={ratingCount}
          averageRating={averageRating}
          onTakeawayClick={() => { setOrderDialogType('takeaway'); setShowOrderDialog(true); }}
          onNavigationClick={() => setShowNavigationDialog(true)}
          brandId={(restaurant as any).brand_id}
          autoTranslateLang={showStoryTranslation ? i18n.language : null}
        />

        {/* Dialogs */}
        <AlertDialog open={showOrderDialog} onOpenChange={setShowOrderDialog}>
          <AlertDialogContent className="max-w-[320px] w-[calc(100%-2rem)] mx-auto border-0 bg-background/80 backdrop-blur-2xl shadow-2xl rounded-[28px] overflow-hidden p-6">
            <div className="absolute inset-0 rounded-[28px] bg-gradient-to-b from-background/40 via-transparent to-transparent pointer-events-none" />
            <AlertDialogHeader className="relative text-center space-y-3">
              <div 
                className="mx-auto w-14 h-14 rounded-2xl bg-gradient-to-br from-primary/10 to-primary/5 flex items-center justify-center shadow-sm shrink-0"
                style={{ transform: 'translateZ(0)', willChange: 'transform' }}
              >
                <ExternalLink className="w-7 h-7 text-primary shrink-0" strokeWidth={1.5} />
              </div>
              <div className="space-y-1.5 px-1">
                <AlertDialogTitle className="text-base font-semibold tracking-tight text-foreground">
                  {orderDialogType === 'takeaway' ? t("restaurant.takeawayOrder", "外卖") : t("restaurant.bookTable", "订台")}
                </AlertDialogTitle>
                <AlertDialogDescription className="text-sm text-muted-foreground/80 leading-relaxed break-words">
                   {t("restaurant.orderOrBookDescription", "即将为您打开餐厅私域页面")}
                 </AlertDialogDescription>
               </div>
             </AlertDialogHeader>
             <AlertDialogFooter className="relative flex-col gap-2 pt-4 mt-1">
                 <AlertDialogAction
                    onClick={async () => {
                      const targetUrl = orderDialogType === 'takeaway' 
                        ? (restaurant as any).takeaway_url 
                        : (restaurant as any).booking_url;
                      if (!targetUrl) return;
                      try {
                        let finalUrl = targetUrl;
                        if (user) {
                          try {
                            const { data } = await supabase.functions.invoke('generate-private-token', {
                              body: { restaurant_id: restaurant.id }
                            });
                            const url = new URL(targetUrl);
                            if (data?.token) {
                              url.searchParams.set('token', data.token);
                            }
                            finalUrl = url.toString();
                          } catch (tokenErr) {
                            console.error('Token generation failed:', tokenErr);
                          }
                        }
                        openExternalUrl(finalUrl);
                      } catch (e) {
                        openExternalUrl(targetUrl);
                      }
                   }}
                   className="w-full rounded-xl h-11 bg-primary hover:bg-primary/90 text-primary-foreground font-medium shadow-lg shadow-primary/25 transition-all duration-200"
                 >
                   {t("common.continue", "继续")}
                 </AlertDialogAction>
               <AlertDialogCancel className="w-full rounded-xl h-11 bg-secondary hover:bg-secondary/80 border-0 text-muted-foreground font-medium transition-all duration-200 mt-0">
                 {t("common.cancel")}
               </AlertDialogCancel>
             </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>

        {/* Login Required Dialog */}
        <AlertDialog open={showLoginDialog} onOpenChange={setShowLoginDialog}>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>{t("activities.loginRequired")}</AlertDialogTitle>
              <AlertDialogDescription>
                {t("activities.loginRequiredMessage")}
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>{t("common.cancel")}</AlertDialogCancel>
              <AlertDialogAction onClick={() => navigate("/auth")}>
                {t("activities.goToLogin")}
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>

        {/* Navigation Confirm Dialog for Ghost Restaurant */}
        <AlertDialog open={showNavigationDialog} onOpenChange={setShowNavigationDialog}>
          <AlertDialogContent className="max-w-[320px] w-[calc(100%-2rem)] mx-auto border-0 bg-background/80 backdrop-blur-2xl shadow-2xl rounded-[28px] overflow-hidden p-6">
            <div className="absolute inset-0 rounded-[28px] bg-gradient-to-b from-background/40 via-transparent to-transparent pointer-events-none" />
            <AlertDialogHeader className="relative text-center space-y-3">
              <div 
                className="mx-auto w-14 h-14 rounded-2xl bg-gradient-to-br from-primary/10 to-primary/5 flex items-center justify-center shadow-sm shrink-0"
                style={{ transform: 'translateZ(0)', willChange: 'transform' }}
              >
                <Navigation className="w-7 h-7 text-primary shrink-0" strokeWidth={1.5} />
              </div>
              <div className="space-y-1.5 px-1">
                <AlertDialogTitle className="text-base font-semibold tracking-tight text-foreground">
                  {t("navigation.confirmTitle")}
                </AlertDialogTitle>
                <AlertDialogDescription className="text-sm text-muted-foreground/80 leading-relaxed break-words">
                  {t("navigation.confirmDescriptionSimple", { destination: localizedRestaurant.name })}
                </AlertDialogDescription>
              </div>
            </AlertDialogHeader>
            <AlertDialogFooter className="relative flex-col gap-2 pt-4 mt-1">
              <AlertDialogAction
                onClick={() => {
                  openNavigation(restaurant.lat, restaurant.lng, localizedRestaurant.name);
                  setShowNavigationDialog(false);
                }}
                className="w-full rounded-xl h-11 bg-primary hover:bg-primary/90 text-primary-foreground font-medium shadow-lg shadow-primary/25 transition-all duration-200"
              >
                {t("navigation.openNavigation", "获取路线")}
              </AlertDialogAction>
              <AlertDialogCancel className="w-full rounded-xl h-11 bg-secondary hover:bg-secondary/80 border-0 text-muted-foreground font-medium transition-all duration-200 mt-0">
                {t("common.cancel")}
              </AlertDialogCancel>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>
      </div>
    );
  }

  const isLandmark = (restaurant as any).template === 'landmark';
  if (isLandmark) {
    return (
      <LandmarkDetailPage
        restaurant={restaurant}
        localizedRestaurant={localizedRestaurant}
        onBack={goBack}
        user={user}
        isFavorite={isFavorite}
        onToggleFavorite={handleToggleFavorite}
        onShare={() => {
          if (isMobile && navigator.share) {
            handleNativeShare();
          } else {
            handleCopyLink();
          }
        }}
        onRefresh={handleRefresh}
      />
    );
  }

  // Regular Restaurant Layout
  return (
    <PullToRefresh onRefresh={handleRefresh}>
    <div className="min-h-screen bg-secondary/20">
      {/* Hero Image */}
      <div className="relative h-[33vh] overflow-hidden bg-muted">
        <img
          src={restaurant.cover_image_url || restaurant.image_url || "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=1200&q=80"}
          alt={localizedRestaurant.name}
          className="w-full h-full object-cover"
          loading="eager"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-background/90 to-transparent" />
        
        {/* Back Button */}
        <Button
          asChild
          variant="secondary"
          size="icon"
          className="absolute top-4 left-4"
        >
          <button onClick={goBack}>
            <ChevronLeft className="w-5 h-5" />
          </button>
        </Button>

        {/* Favorite Button */}
        {user && (
          <Button
            variant="secondary"
            size="icon"
            className="absolute top-4 right-4"
            onClick={handleToggleFavorite}
          >
            <Heart className={`w-5 h-5 ${isFavorite ? 'fill-destructive text-destructive' : ''}`} />
          </Button>
        )}
        
        {/* Share Button */}
        {isMobile && navigator.share ? (
          <Button
            variant="secondary"
            size="icon"
            className={`absolute top-4 shadow-lg ${user ? 'right-16' : 'right-4'}`}
            onClick={() => {
              if (!user) {
                setShowLoginDialog(true);
                return;
              }
              handleNativeShare();
            }}
          >
            <Share2 className="w-5 h-5" />
          </Button>
        ) : (
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                variant="secondary"
                size="icon"
                className={`absolute top-4 shadow-lg ${user ? 'right-16' : 'right-4'}`}
                onClick={(e) => {
                  if (!user) {
                    e.preventDefault();
                    setShowLoginDialog(true);
                  }
                }}
              >
                <Share2 className="w-5 h-5" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end" className="w-48">
              {navigator.share && (
                <>
                  <DropdownMenuItem onClick={handleNativeShare}>
                    <Share2 className="w-4 h-4 mr-2" />
                    {t("common.moreOptions")}
                  </DropdownMenuItem>
                  <DropdownMenuSeparator />
                </>
              )}
              <DropdownMenuItem onClick={() => handleShareToPlatform("wechat")}>
                <MessageCircle className="w-4 h-4 mr-2" />
                WeChat
              </DropdownMenuItem>
              <DropdownMenuItem onClick={() => handleShareToPlatform("whatsapp")}>
                <MessageCircle className="w-4 h-4 mr-2" />
                WhatsApp
              </DropdownMenuItem>
              <DropdownMenuItem onClick={() => handleShareToPlatform("facebook")}>
                <Share2 className="w-4 h-4 mr-2" />
                Facebook
              </DropdownMenuItem>
              <DropdownMenuItem onClick={() => handleShareToPlatform("twitter")}>
                <Share2 className="w-4 h-4 mr-2" />
                X (Twitter)
              </DropdownMenuItem>
              <DropdownMenuItem onClick={() => handleShareToPlatform("telegram")}>
                <MessageCircle className="w-4 h-4 mr-2" />
                Telegram
              </DropdownMenuItem>
              <DropdownMenuSeparator />
              <DropdownMenuItem onClick={handleCopyLink}>
                <Link2 className="w-4 h-4 mr-2" />
                {t("common.copyLink")}
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        )}
        
        {/* Edit Button for Merchants */}
        {(isMerchantOfRestaurant || isAdmin) && restaurant && (
          <RestaurantFormDialog
            restaurant={restaurant}
            trigger={
              <Button
                variant="secondary"
                size="icon"
                className={`absolute top-4 ${user ? 'right-28' : 'right-16'}`}
              >
                <Edit className="w-5 h-5" />
              </Button>
            }
          />
        )}
        
        {/* Report Button */}
        {restaurant && (
          <ReportDialog
            targetType="restaurant"
            targetId={restaurant.id}
            onLoginRequired={() => setShowLoginDialog(true)}
            trigger={
              <Button
                variant="secondary"
                size="icon"
                className={`absolute top-4 ${
                  (isMerchantOfRestaurant || isAdmin) 
                    ? (user ? 'right-40' : 'right-28')
                    : (user ? 'right-28' : 'right-16')
                }`}
              >
                <ShieldAlert className="w-5 h-5" />
              </Button>
            }
          />
        )}
      </div>

      <div className="container mx-auto max-w-6xl px-4 -mt-20 relative z-10 pb-12">
        <Card className="shadow-large">
          <CardHeader>
            <div className="flex flex-col md:flex-row md:items-start md:justify-between gap-4">
              <div>
                <div className="mb-2 flex flex-wrap gap-2">
                  {localizedRestaurant.type.slice(0, 3).map((type, idx) => (
                    <Badge key={idx} variant="secondary">{type}</Badge>
                  ))}
                </div>
                <CardTitle className="text-3xl mb-2 flex items-center gap-2 flex-wrap">
                  {translatedName || formatTrademarkSymbols(localizedRestaurant.name)}
                  {(restaurant as any).store_level === 'complete' && (
                    <button
                      className="inline-flex items-center justify-center bg-primary/90 backdrop-blur-sm rounded-full p-1.5 shadow-md hover:bg-primary transition-colors"
                      onClick={() => setVerifiedDialog(true)}
                      title={t("restaurants.verifiedStore")}
                    >
                      <BadgeCheck className="w-5 h-5 text-primary-foreground" />
                    </button>
                  )}
                  {(restaurant as any).store_level === 'shell' && (
                    <button
                      className="inline-flex items-center gap-1 bg-primary/90 backdrop-blur-sm rounded-full px-2.5 py-1 shadow-sm hover:bg-primary transition-colors"
                      onClick={() => {
                        if (!requireLogin()) return;
                        setClaimDialog({
                          id: restaurant.id,
                          name: restaurant.name,
                          address: restaurant.address,
                        });
                      }}
                      title={t("restaurants.unclaimedStore", "未认领")}
                    >
                      <HandMetal className="w-4 h-4 text-primary-foreground" />
                      <span className="text-xs font-medium text-primary-foreground">{t("restaurants.unclaimedStore", "未认领")}</span>
                    </button>
                  )}
                </CardTitle>
                <div className="flex items-center gap-3 mb-2 flex-wrap">
                  {distance !== null && (
                    <div className="flex items-center gap-1">
                      <Navigation className="w-4 h-4 text-primary" />
                      <span className="font-semibold text-base">{distance.toFixed(1)} km</span>
                    </div>
                  )}
                  <div className="flex items-center gap-1">
                    <Star className={`w-5 h-5 ${ratingCount > 0 ? "fill-accent text-accent" : "text-muted-foreground"}`} />
                    {ratingCount > 0 ? (
                      <span className="font-semibold text-base">
                        {averageRating.toFixed(1)}
                        <span className="text-muted-foreground font-normal text-sm ml-1">({ratingCount})</span>
                      </span>
                    ) : (
                      <span className="text-sm text-muted-foreground">
                        {t("restaurant.noRatingWithHint")}
                      </span>
                    )}
                  </div>
                  {priceRangeDisplay && (
                    <div className="flex items-center gap-1">
                      <Wallet className="w-4 h-4 text-primary" />
                      <span className="font-semibold text-base">{priceRangeDisplay}</span>
                    </div>
                  )}
                  
                  {/* Translate - inline chip matching info row style */}
                  <div className="flex items-center gap-1">
                    <button
                      className={`inline-flex items-center gap-1 min-h-[32px] py-1 px-2 rounded-md text-xs font-medium transition-all duration-200 active:scale-95 ${
                        (isStoryTranslating || isRegularTranslating)
                          ? "text-muted-foreground cursor-wait" 
                          : showStoryTranslation 
                            ? "text-primary bg-primary/10" 
                            : "text-muted-foreground hover:text-primary active:text-primary"
                      }`}
                      disabled={isStoryTranslating || isRegularTranslating}
                      onClick={async () => {
                        const targetLang = i18n.language;
                        if (showStoryTranslation) {
                          setTranslatedName(null);
                          setTranslatedAddress(null);
                          setTranslatedDescription(null);
                          translateStory(targetLang);
                          return;
                        }
                        setIsRegularTranslating(true);
                        try {
                          const parts = [localizedRestaurant.name];
                          if (restaurant.address) parts.push(restaurant.address);
                          const desc = localizedRestaurant.description?.replace(/<[^>]*>/g, '').trim();
                          if (desc) parts.push(localizedRestaurant.description);
                          const combined = parts.join('\n---SECTION---\n');
                          
                          try {
                            const { data, error } = await supabase.functions.invoke('translate-content', {
                              body: { text: combined, targetLang }
                            });
                            if (!error && data?.translatedText) {
                              const splitParts = data.translatedText.split(/---SECTION---/);
                              setTranslatedName(splitParts[0]?.trim() || null);
                              setTranslatedAddress(splitParts[1]?.trim() || null);
                              setTranslatedDescription(splitParts[2]?.trim() || null);
                            }
                          } catch {}
                          await translateStory(targetLang);
                        } finally {
                          setIsRegularTranslating(false);
                        }
                      }}
                    >
                      {(isStoryTranslating || isRegularTranslating) ? (
                        <Loader2 className="h-3.5 w-3.5 animate-spin" />
                      ) : showStoryTranslation ? (
                        <RotateCcw className="h-3.5 w-3.5" />
                      ) : (
                        <Languages className="h-3.5 w-3.5" />
                      )}
                      <span>
                        {(isStoryTranslating || isRegularTranslating)
                          ? t("translate.translating", "翻译中...") 
                          : showStoryTranslation 
                            ? t("translate.showOriginal", "显示原文") 
                            : t("translate.button", "翻译")}
                      </span>
                    </button>
                  </div>
                </div>
                
                {/* Brand About Section - Collapsible */}
                {(restaurant as any).brand_id && (
                  <BrandAboutSection 
                    brandId={(restaurant as any).brand_id} 
                    autoTranslateLang={showStoryTranslation ? i18n.language : null}
                  />
                )}
                
                {localizedRestaurant.description && localizedRestaurant.description.replace(/<[^>]*>/g, '').trim() !== '' && (
                  <div 
                    className="text-muted-foreground prose prose-sm dark:prose-invert max-w-none [&_*]:!text-inherit [&_a]:!text-primary [&_a]:underline mt-3"
                    dangerouslySetInnerHTML={{ __html: translatedDescription || localizedRestaurant.description }}
                  />
                )}
              </div>
            </div>
          </CardHeader>

          <CardContent className="space-y-6">
            {/* Building Story - Core narrative content */}
            <BuildingStorySection
              restaurant={restaurant}
              variant="card"
              narrativeOverride={narrativeDisplay}
              onTranslateClick={async () => {
                const targetLang = i18n.language;
                if (showStoryTranslation) {
                  setTranslatedName(null);
                  setTranslatedAddress(null);
                  setTranslatedDescription(null);
                  translateStory(targetLang);
                  return;
                }
                setIsRegularTranslating(true);
                try {
                  const parts = [localizedRestaurant.name];
                  if (restaurant.address) parts.push(restaurant.address);
                  const desc = localizedRestaurant.description?.replace(/<[^>]*>/g, '').trim();
                  if (desc) parts.push(localizedRestaurant.description);
                  const combined = parts.join('\n---SECTION---\n');
                  try {
                    const { data, error } = await supabase.functions.invoke('translate-content', {
                      body: { text: combined, targetLang }
                    });
                    if (!error && data?.translatedText) {
                      const splitParts = data.translatedText.split(/---SECTION---/);
                      setTranslatedName(splitParts[0]?.trim() || null);
                      setTranslatedAddress(splitParts[1]?.trim() || null);
                      setTranslatedDescription(splitParts[2]?.trim() || null);
                    }
                  } catch {}
                  await translateStory(targetLang);
                } finally {
                  setIsRegularTranslating(false);
                }
              }}
              isTranslating={isStoryTranslating || isRegularTranslating}
              showTranslation={showStoryTranslation}
            />

            {/* Separator with icon - Visual division between story and action buttons */}
            <div className="relative my-3">
              <Separator />
              <div className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 bg-background px-3">
                <UtensilsCrossed className="h-4 w-4 text-muted-foreground" />
              </div>
            </div>

            {/* Takeaway & Booking Buttons - Below Story */}
            {(() => {
              const hasTakeaway = !!(restaurant as any).takeaway_url && !!(restaurant as any).show_takeaway_button;
              const hasBooking = !!(restaurant as any).booking_url && !!(restaurant as any).show_booking_button && (restaurant as any).template !== 'ghost' && (restaurant as any).template !== 'michelin';
              if (!hasTakeaway && !hasBooking) return null;
              const bothVisible = hasTakeaway && hasBooking;
              return (
                <div className={bothVisible ? "grid grid-cols-2 gap-3" : "flex"}>
                  {hasTakeaway && (
                    <Button 
                      className="w-full h-12 rounded-xl bg-primary text-primary-foreground hover:bg-primary/90"
                      onClick={() => { setOrderDialogType('takeaway'); setShowOrderDialog(true); }}
                    >
                      <ShoppingBag className="w-4 h-4 mr-2" />
                      {t("restaurant.takeawayOrder", "外卖")}
                    </Button>
                  )}
                  {hasBooking && (
                    <Button 
                      className="w-full h-12 rounded-xl bg-primary text-primary-foreground hover:bg-primary/90"
                      onClick={() => { setOrderDialogType('booking'); setShowOrderDialog(true); }}
                    >
                      <UtensilsCrossed className="w-4 h-4 mr-2" />
                      {t("restaurant.bookTable", "订台")}
                    </Button>
                  )}
                </div>
              );
            })()}

            {/* Official Website Button - Below Takeaway & Booking */}
            {(restaurant as any).official_website && (
              <Button 
                variant="outline"
                className="w-full h-12 rounded-xl"
                onClick={() => {
                  window.open((restaurant as any).official_website, '_blank', 'noopener,noreferrer');
                }}
              >
                <Globe className="w-4 h-4 mr-2" />
                {t("restaurant.officialWebsite", "官网")}
              </Button>
            )}

            {/* Menu Section - Images or PDF */}
            {(() => {
              const menuImages = (restaurant as any).menu_images as string[] | null;
              const menuPdfUrl = (restaurant as any).menu_pdf_url as string | null;
              const hasMenu = (menuImages && menuImages.length > 0) || menuPdfUrl;
              if (!hasMenu) return null;
              return (
                <Collapsible>
                  <CollapsibleTrigger className="flex items-center justify-between w-full p-4 rounded-lg bg-muted/50 hover:bg-muted/80 transition-colors">
                    <div className="flex items-center gap-3">
                      <UtensilsCrossed className="w-5 h-5 text-primary" />
                      <span className="font-medium text-card-foreground">{t("restaurant.menu", "菜单")}</span>
                    </div>
                    <ChevronDown className="w-5 h-5 text-muted-foreground transition-transform [[data-state=open]>&]:rotate-180" />
                  </CollapsibleTrigger>
                  <CollapsibleContent className="mt-3 space-y-3">
                    <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-2">
                      {menuPdfUrl && (
                        <div
                          className="aspect-square rounded-lg overflow-hidden cursor-pointer hover:opacity-90 transition-opacity border border-border bg-muted relative flex flex-col items-center justify-center gap-2"
                          onClick={() => window.open(menuPdfUrl, '_blank', 'noopener,noreferrer')}
                        >
                          <FileText className="w-10 h-10 text-primary" />
                          <span className="text-xs font-medium text-foreground">{t("restaurant.viewMenu", "查看菜单")}</span>
                          <div className="absolute bottom-0 inset-x-0 bg-background/80 backdrop-blur-sm py-1 text-center">
                            <span className="text-xs font-medium text-muted-foreground">PDF</span>
                          </div>
                        </div>
                      )}
                      {menuImages && menuImages.map((url, idx) => (
                        <div
                          key={idx}
                          className="aspect-square rounded-lg overflow-hidden cursor-pointer hover:opacity-90 transition-opacity border border-border"
                          onClick={() => setMenuPreviewUrl(url)}
                        >
                          <img
                            src={url}
                            alt={`${t("restaurant.menu", "菜单")} ${idx + 1}`}
                            className="w-full h-full object-cover"
                            loading="lazy"
                          />
                        </div>
                      ))}
                    </div>
                    <ImagePreviewModal
                      imageUrl={menuPreviewUrl || ""}
                      isOpen={!!menuPreviewUrl}
                      onClose={() => setMenuPreviewUrl(null)}
                    />
                  </CollapsibleContent>
                </Collapsible>
              );
            })()}

            {/* Contact Info */}
            <div className="grid md:grid-cols-2 gap-4">
              {/* Activities */}
              {restaurantActivities.length > 0 && (
                <Collapsible
                  open={activitiesOpen}
                  onOpenChange={setActivitiesOpen}
                  className="flex items-start gap-3 p-4 rounded-lg bg-muted/50"
                >
                  <Star className="w-5 h-5 text-primary mt-0.5 flex-shrink-0" />
                  <div className="flex-1">
                    <CollapsibleTrigger className="w-full">
                      <div className="flex items-center justify-between">
                        <div className="flex flex-col items-start">
                          <p className="font-medium text-card-foreground">{t("activities.title")}</p>
                          {!activitiesOpen && (
                            <div className="flex flex-wrap gap-1.5 mt-1">
                              {restaurantActivities.map((activity, idx) => (
                                <Badge 
                                  key={`activity-${idx}`} 
                                  variant="default" 
                                  className="text-white"
                                  style={{ backgroundColor: activity.badge_color || "#9b87f5" }}
                                >
                                  {getLocalizedBadgeText(activity, i18n.language)}
                                </Badge>
                              ))}
                            </div>
                          )}
                        </div>
                        <ChevronDown className={`w-5 h-5 text-muted-foreground transition-transform ${activitiesOpen ? 'rotate-180' : ''}`} />
                      </div>
                    </CollapsibleTrigger>
                    <CollapsibleContent className="mt-3 space-y-2">
                      {restaurantActivities.map((activity, idx) => {
                        const intro = getLocalizedIntro(activity, i18n.language);
                        return (
                          <Link
                            key={`activity-detail-${idx}`}
                            to={`/activity/${activity.activity_id}`}
                            className="block p-2 rounded-md hover:bg-muted/80 transition-colors"
                          >
                            <Badge 
                              variant="default" 
                              className="text-white mr-2"
                              style={{ backgroundColor: activity.badge_color || "#9b87f5" }}
                            >
                              {getLocalizedBadgeText(activity, i18n.language)}
                            </Badge>
                            <span className="text-sm text-muted-foreground">
                              {intro || getLocalizedActivityTitle(activity, i18n.language)} ... →
                            </span>
                          </Link>
                        );
                      })}
                    </CollapsibleContent>
                  </div>
                </Collapsible>
              )}

              <div className="flex flex-col gap-3 p-4 rounded-lg bg-muted/50">
                {/* Row 1: Icon + Address */}
                <div className="flex items-start gap-3">
                  <MapPin className="w-5 h-5 text-primary mt-0.5 flex-shrink-0" />
                  <div className="flex-1">
                    <p className="font-medium text-card-foreground">{t("restaurant.address")}</p>
                    <div className="flex items-center gap-2">
                      <p className="text-muted-foreground">{translatedAddress || restaurant.address}</p>
                      {((restaurant as any).template === 'ghost' || (restaurant as any).template === 'michelin') && (
                        <Badge variant="secondary" className="text-xs">
                          {t("restaurants.ghostKitchen")}
                        </Badge>
                      )}
                    </div>
                  </div>
                </div>
                {/* Row 2: Navigation Button (Mobile only) */}
                {isMobile && (restaurant as any).template !== 'ghost' && (restaurant as any).template !== 'michelin' && (
                  <Button 
                    variant="secondary"
                    size="sm"
                    className="w-full rounded-lg"
                    onClick={() => setShowNavigationDialog(true)}
                  >
                    <Navigation className="w-4 h-4 mr-2" />
                    {t("restaurant.getDirections")}
                  </Button>
                )}
              </div>

              {restaurant.phone && (
                <a 
                  href={`tel:${restaurant.phone}`}
                  className="flex items-start gap-3 p-4 rounded-lg bg-muted/50 hover:bg-muted/80 transition-colors cursor-pointer"
                >
                  <Phone className="w-5 h-5 text-primary mt-0.5 flex-shrink-0" />
                  <div>
                    <p className="font-medium text-card-foreground">{t("restaurant.phone")}</p>
                    <p className="text-primary underline">{restaurant.phone}</p>
                  </div>
                </a>
              )}

              {/* Opening Hours - Only for non-ghost restaurants */}
              {restaurant.opening_hours && (restaurant as any).template !== 'ghost' && (restaurant as any).template !== 'michelin' && (
                <Collapsible
                  open={hoursOpen}
                  onOpenChange={setHoursOpen}
                  className="flex items-start gap-3 p-4 rounded-lg bg-muted/50"
                >
                  <Clock className="w-5 h-5 text-primary mt-0.5 flex-shrink-0" />
                  <div className="flex-1">
                    <CollapsibleTrigger className="w-full">
                      <div className="flex items-center justify-between">
                        <div className="flex flex-col items-start">
                          <p className="font-medium text-card-foreground">{t("restaurant.hours")}</p>
                          {!hoursOpen && (
                            <p className="text-sm text-muted-foreground mt-0.5">
                              {t("restaurant.today")} {formatOpeningHours(restaurant.opening_hours)}
                            </p>
                          )}
                        </div>
                        <ChevronDown className={`w-5 h-5 text-muted-foreground transition-transform ${hoursOpen ? 'rotate-180' : ''}`} />
                      </div>
                    </CollapsibleTrigger>
                    <CollapsibleContent className="mt-3">
                      <div className="space-y-2">
                        {(() => {
                          const days = ['monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday', 'sunday'];
                          const dayKeys: Record<string, string> = {
                            monday: 'dayMon',
                            tuesday: 'dayTue',
                            wednesday: 'dayWed',
                            thursday: 'dayThu',
                            friday: 'dayFri',
                            saturday: 'daySat',
                            sunday: 'daySun'
                          };
                          const currentDay = days[new Date().getDay() === 0 ? 6 : new Date().getDay() - 1];
                          
                          return days.map((day) => {
                            const hours = restaurant.opening_hours[day];
                            const isToday = day === currentDay;
                            const displayName = t(`restaurant.${dayKeys[day]}`);
                            
                            let hoursText = 'N/A';
                            if (hours) {
                              if (hours.closed) {
                                hoursText = t("restaurant.closed");
                              } else if (hours.splitShift) {
                                hoursText = `${hours.open} - ${hours.close}, ${hours.open2} - ${hours.close2}`;
                              } else {
                                hoursText = `${hours.open} - ${hours.close}`;
                              }
                            }
                            
                            return (
                              <div 
                                key={day}
                                className={`flex justify-between items-center py-1.5 px-2 rounded ${
                                  isToday ? 'bg-primary/10 border border-primary/20' : ''
                                }`}
                              >
                                <span className={`text-sm font-medium ${
                                  isToday ? 'text-primary' : 'text-foreground'
                                }`}>
                                  {displayName}
                                  {isToday && <span className="ml-2 text-xs">({t("restaurant.today")})</span>}
                                </span>
                                <span className={`text-sm ${
                                  isToday ? 'text-primary font-semibold' : 'text-muted-foreground'
                                } ${hours?.closed ? 'italic' : ''}`}>
                                  {hoursText}
                                </span>
                              </div>
                            );
                          });
                        })()}
                      </div>
                    </CollapsibleContent>
                  </div>
                </Collapsible>
              )}

              {/* Announcement */}
              {restaurant && (getLocalizedField(restaurant, "announcement") || restaurant.announcement_zh) && (
                <Collapsible
                  open={announcementOpen}
                  onOpenChange={setAnnouncementOpen}
                  className="flex items-start gap-3 p-4 rounded-lg bg-muted/50"
                >
                  <MessageCircle className="w-5 h-5 text-primary mt-0.5 flex-shrink-0" />
                  <div className="flex-1">
                    <CollapsibleTrigger className="w-full">
                      <div className="flex items-center justify-between">
                        <p className="font-medium text-card-foreground">{t("restaurant.announcement")}</p>
                        <ChevronDown className={`w-5 h-5 text-muted-foreground transition-transform ${announcementOpen ? 'rotate-180' : ''}`} />
                      </div>
                    </CollapsibleTrigger>
                    <CollapsibleContent className="mt-3">
                      <div className="p-3 rounded-md bg-primary/5 border border-primary/10">
                        <p className="text-sm text-foreground whitespace-pre-wrap">
                          {getLocalizedField(restaurant, "announcement") || restaurant.announcement_zh}
                        </p>
                      </div>
                    </CollapsibleContent>
                  </div>
                </Collapsible>
              )}
            </div>

            {/* Action Buttons - Hide navigation/booking for ghost restaurants */}
            <div className="flex flex-col gap-3">
              {/* Row 1: 获取路线 - Desktop only */}
              {!isMobile && (restaurant as any).template !== 'ghost' && (restaurant as any).template !== 'michelin' && (
                <Button 
                  variant="secondary"
                  className="w-full h-12 rounded-xl"
                  onClick={() => setShowNavigationDialog(true)}
                >
                  <Navigation className="w-4 h-4 mr-2" />
                  {t("restaurant.getDirections")}
                </Button>
              )}
            </div>

            {/* Navigation Confirm Dialog - Glass UI Style */}
            <AlertDialog open={showNavigationDialog} onOpenChange={setShowNavigationDialog}>
              <AlertDialogContent className="max-w-[320px] w-[calc(100%-2rem)] mx-auto border-0 bg-background/80 backdrop-blur-2xl shadow-2xl rounded-[28px] overflow-hidden p-6">
                {/* Glass effect overlay */}
                <div className="absolute inset-0 rounded-[28px] bg-gradient-to-b from-background/40 via-transparent to-transparent pointer-events-none" />
                
                <AlertDialogHeader className="relative text-center space-y-3">
                  {/* Icon container */}
                  <div 
                    className="mx-auto w-14 h-14 rounded-2xl bg-gradient-to-br from-primary/10 to-primary/5 flex items-center justify-center shadow-sm shrink-0"
                    style={{ transform: 'translateZ(0)', willChange: 'transform' }}
                  >
                    <Navigation className="w-7 h-7 text-primary shrink-0" strokeWidth={1.5} />
                  </div>
                  <div className="space-y-1.5 px-1">
                    <AlertDialogTitle className="text-base font-semibold tracking-tight text-foreground">
                      {t("navigation.confirmTitle")}
                    </AlertDialogTitle>
                    <AlertDialogDescription className="text-sm text-muted-foreground/80 leading-relaxed break-words">
                      {t("navigation.confirmDescriptionSimple", { destination: localizedRestaurant.name })}
                    </AlertDialogDescription>
                  </div>
                </AlertDialogHeader>
                
                <AlertDialogFooter className="relative flex-col gap-2 pt-4 mt-1">
                  <AlertDialogAction
                    onClick={() => {
                      openNavigation(restaurant.lat, restaurant.lng, localizedRestaurant.name);
                      setShowNavigationDialog(false);
                    }}
                    className="w-full rounded-xl h-11 bg-primary hover:bg-primary/90 text-primary-foreground font-medium shadow-lg shadow-primary/25 transition-all duration-200"
                  >
                    {t("navigation.openNavigation", "获取路线")}
                  </AlertDialogAction>
                  <AlertDialogCancel className="w-full rounded-xl h-11 bg-secondary hover:bg-secondary/80 border-0 text-muted-foreground font-medium transition-all duration-200 mt-0">
                    {t("common.cancel")}
                  </AlertDialogCancel>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>

            {/* Private Domain Confirm Dialog - Glass UI Style */}
            <AlertDialog open={showPrivateDialog} onOpenChange={setShowPrivateDialog}>
              <AlertDialogContent className="max-w-xs w-[calc(100%-3rem)] mx-auto border-0 bg-white/70 dark:bg-gray-900/70 backdrop-blur-xl shadow-2xl rounded-3xl overflow-hidden">
                {/* Glass effect overlay */}
                <div className="absolute inset-0 rounded-3xl bg-gradient-to-b from-white/30 via-transparent to-transparent pointer-events-none" />
                
                <AlertDialogHeader className="relative text-center pb-2">
                  {/* Icon container */}
                  <div 
                    className="mx-auto mb-4 w-14 h-14 rounded-2xl bg-gradient-to-br from-primary/20 to-primary/10 flex items-center justify-center shadow-inner shrink-0"
                    style={{ transform: 'translateZ(0)', willChange: 'transform' }}
                  >
                    <ExternalLink className="w-7 h-7 text-primary shrink-0" strokeWidth={2} />
                  </div>
                  <AlertDialogTitle className="text-lg font-semibold text-foreground">
                    {t("restaurant.joinPrivateTitle")}
                  </AlertDialogTitle>
                  <AlertDialogDescription className="text-center text-sm text-muted-foreground mt-2 leading-relaxed">
                    {t("restaurant.joinPrivateDescription")}
                  </AlertDialogDescription>
                </AlertDialogHeader>
                
                <AlertDialogFooter className="relative flex-col gap-2 pt-4">
                  <AlertDialogAction
                     onClick={async () => {
                      const url = new URL((restaurant as any).takeaway_url);
                      if (user) {
                        try {
                          const { data } = await supabase.functions.invoke('generate-private-token', {
                            body: { restaurant_id: restaurant.id }
                          });
                          if (data?.token) {
                            url.searchParams.set('token', data.token);
                          }
                        } catch (tokenErr) {
                          console.error('Token generation failed:', tokenErr);
                        }
                      }
                      const targetUrl = url.toString();
                      openExternalUrl(targetUrl);
                    }}
                    className="w-full rounded-xl py-3 bg-primary hover:bg-primary/90 text-primary-foreground font-medium shadow-lg shadow-primary/20 transition-all duration-200"
                  >
                    {isGeneratingToken ? (
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                    ) : null}
                    {t("restaurant.joinPrivateConfirm")}
                  </AlertDialogAction>
                  <AlertDialogCancel className="w-full rounded-xl py-3 bg-white/50 dark:bg-white/10 hover:bg-white/70 dark:hover:bg-white/20 border-0 text-muted-foreground font-medium transition-all duration-200">
                    {t("common.cancel")}
                  </AlertDialogCancel>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>

            {/* Order/Booking Confirm Dialog - Glass UI Style */}
            <AlertDialog open={showOrderDialog} onOpenChange={setShowOrderDialog}>
              <AlertDialogContent className="max-w-[320px] w-[calc(100%-2rem)] mx-auto border-0 bg-background/80 backdrop-blur-2xl shadow-2xl rounded-[28px] overflow-hidden p-6">
                <div className="absolute inset-0 rounded-[28px] bg-gradient-to-b from-background/40 via-transparent to-transparent pointer-events-none" />
                <AlertDialogHeader className="relative text-center space-y-3">
                  <div 
                    className="mx-auto w-14 h-14 rounded-2xl bg-gradient-to-br from-primary/10 to-primary/5 flex items-center justify-center shadow-sm shrink-0"
                    style={{ transform: 'translateZ(0)', willChange: 'transform' }}
                  >
                    <ExternalLink className="w-7 h-7 text-primary shrink-0" strokeWidth={1.5} />
                  </div>
                  <div className="space-y-1.5 px-1">
                    <AlertDialogTitle className="text-base font-semibold tracking-tight text-foreground">
                      {orderDialogType === 'takeaway' ? t("restaurant.takeawayOrder", "外卖") : t("restaurant.bookTable", "订台")}
                    </AlertDialogTitle>
                    <AlertDialogDescription className="text-sm text-muted-foreground/80 leading-relaxed break-words">
                       {t("restaurant.orderOrBookDescription", "即将为您打开餐厅私域页面")}
                     </AlertDialogDescription>
                   </div>
                 </AlertDialogHeader>
                 <AlertDialogFooter className="relative flex-col gap-2 pt-4 mt-1">
                     <AlertDialogAction
                        onClick={async () => {
                          const targetUrl = orderDialogType === 'takeaway' 
                            ? (restaurant as any).takeaway_url 
                            : (restaurant as any).booking_url;
                          if (!targetUrl) return;
                          try {
                            let finalUrl = targetUrl;
                            if (user) {
                              try {
                                const { data } = await supabase.functions.invoke('generate-private-token', {
                                  body: { restaurant_id: restaurant.id }
                                });
                                const url = new URL(targetUrl);
                                if (data?.token) {
                                  url.searchParams.set('token', data.token);
                                }
                                finalUrl = url.toString();
                              } catch (tokenErr) {
                                console.error('Token generation failed:', tokenErr);
                              }
                            }
                            openExternalUrl(finalUrl);
                          } catch (e) {
                            openExternalUrl(targetUrl);
                          }
                       }}
                       className="w-full rounded-xl h-11 bg-primary hover:bg-primary/90 text-primary-foreground font-medium shadow-lg shadow-primary/25 transition-all duration-200"
                     >
                       {t("common.continue", "继续")}
                     </AlertDialogAction>
                   <AlertDialogCancel className="w-full rounded-xl h-11 bg-secondary hover:bg-secondary/80 border-0 text-muted-foreground font-medium transition-all duration-200 mt-0">
                     {t("common.cancel")}
                   </AlertDialogCancel>
                 </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>

            {/* Dish Photo Gallery */}
            <RestaurantDishGallery restaurantId={restaurant.id} showGallery={(restaurant as any).show_dish_gallery !== false} />

            {/* Store Ad Banner - Only for unclaimed stores, not for michelin */}
            {(restaurant as any).template !== 'michelin' && (
              <StoreAdBanner country={(restaurant as any).country || null} city={(restaurant as any).city || null} storeLevel={(restaurant as any).store_level || 'shell'} />
            )}

            {/* Map - Only show for non-ghost restaurants */}
            {(restaurant as any).template !== 'ghost' && (restaurant as any).template !== 'michelin' && (
              <div ref={mapSectionRef}>
                <Collapsible
                  open={mapOpen}
                  onOpenChange={setMapOpen}
                  className="p-4 rounded-lg bg-muted/50"
                >
                  <CollapsibleTrigger className="w-full">
                    <div className="flex items-center justify-between mb-4">
                      <h2 className="text-2xl font-bold">{t("restaurant.map")}</h2>
                      <ChevronDown className={`w-5 h-5 text-muted-foreground transition-transform ${mapOpen ? 'rotate-180' : ''}`} />
                    </div>
                  </CollapsibleTrigger>
                  <CollapsibleContent>
                    {shouldLoadMap ? (
                      <div ref={mapContainer} className="h-[350px] rounded-lg overflow-hidden bg-muted" />
                    ) : (
                      <div className="h-[350px] rounded-lg bg-muted flex items-center justify-center">
                        <Loader2 className="w-6 h-6 animate-spin text-muted-foreground" />
                      </div>
                    )}
                  </CollapsibleContent>
                </Collapsible>
              </div>
            )}

            <Separator />

            {/* Rating Section */}
            <RestaurantRating restaurantId={restaurant.id} />

            <Separator />

            {/* Comments Section */}
            <div ref={commentsSectionRef}>
              {shouldLoadComments ? (
                <Suspense fallback={
                  <div className="flex items-center justify-center py-12">
                    <Loader2 className="w-8 h-8 animate-spin text-primary" />
                  </div>
                }>
                  <RestaurantComments restaurantId={restaurant.id} />
                </Suspense>
              ) : (
                <div className="flex items-center justify-center py-12">
                  <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
                </div>
              )}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Login Required Dialog */}
      <AlertDialog open={showLoginDialog} onOpenChange={setShowLoginDialog}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{t("activities.loginRequired")}</AlertDialogTitle>
            <AlertDialogDescription>
              {t("activities.loginRequiredMessage")}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t("common.cancel")}</AlertDialogCancel>
            <AlertDialogAction onClick={() => navigate("/auth")}>
              {t("activities.goToLogin")}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
      
      {/* Smart Share Drawer for WebView environments */}
      {SmartShareDrawer}

      {/* Verified Store Dialog */}
      <Dialog open={verifiedDialog} onOpenChange={setVerifiedDialog}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <BadgeCheck className="w-5 h-5 text-primary fill-primary/10" />
              {t("restaurants.verifiedStore")}
            </DialogTitle>
            <DialogDescription className="text-sm leading-relaxed pt-2">
              {t("restaurants.verifiedStoreDesc")}
            </DialogDescription>
          </DialogHeader>
        </DialogContent>
      </Dialog>

      {/* Claim Restaurant Dialog */}
      <ClaimRestaurantDialog
        open={!!claimDialog}
        onOpenChange={(open) => !open && setClaimDialog(null)}
        restaurant={claimDialog}
      />
    </div>
    </PullToRefresh>
  );
};

export default RestaurantDetail;
